import 'package:flutter/material.dart';
import 'package:task_manager_flutter/data/utils/api_links.dart';
import 'package:task_manager_flutter/data/models/network_response.dart';
import 'package:task_manager_flutter/data/services/network_caller.dart';
import 'package:task_manager_flutter/ui/widgets/generic_grid_screen.dart';

class Login {
  int? id;
  String? email;
  String? senha;
  String? nome;
  String? cpfCnpj;
  List<Role>? roles;
  LoginEnum? tipoLogin;
  Empresa? empresa;
  Parceiro? parceiro;
  Aplicativo? aplicativo;
  DateTime? dhCreatedAt;
  DateTime? dhUpdatedAt;

  Login({
    this.id,
    this.email,
    this.senha,
    this.nome,
    this.cpfCnpj,
    this.roles,
    this.tipoLogin,
    this.empresa,
    this.parceiro,
    this.aplicativo,
    this.dhCreatedAt,
    this.dhUpdatedAt,
  });

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'email': email,
      'senha': senha,
      'nome': nome,
      'cpfCnpj': cpfCnpj,
      'roles': roles?.map((role) => role.toJson()).toList(),
      'tipoLogin': tipoLogin?.index,
      'empresa': empresa?.toJson(),
      'parceiro': parceiro?.toJson(),
      'aplicativo': aplicativo?.toJson(),
      'dhCreatedAt': dhCreatedAt?.toIso8601String(),
      'dhUpdatedAt': dhUpdatedAt?.toIso8601String(),
    };
  }

  Login.fromJson(Map<String, dynamic> json) {
    if (json.isNotEmpty) {
      id = json['id'];
      email = json['email'];
      senha = json['senha'];
      nome = json['nome'];
      cpfCnpj = json['cpfCnpj'];
      roles = json['roles'] != null
          ? (json['roles'] as List).map((i) => Role.fromJson(i)).toList()
          : null;
      tipoLogin = LoginEnum.values[json['tipoLogin'] ?? 0];
      empresa = json['empresa'] != null ? Empresa.fromJson(json['empresa']) : null;
      parceiro = json['parceiro'] != null ? Parceiro.fromJson(json['parceiro']) : null;
      aplicativo = json['aplicativo'] != null ? Aplicativo.fromJson(json['aplicativo']) : null;
      dhCreatedAt = DateTime.parse(json['dhCreatedAt']);
      dhUpdatedAt = DateTime.parse(json['dhUpdatedAt']);
    }
  }

  static List<FieldConfig> fieldConfigs = [
    FieldConfig(
      label: "Email",
      fieldName: "email",
      icon: Icons.email,
      isFilterable: true,
      isInForm: true,
      isRequired: true,
      validator: (value) {
        if (value == null || value.isEmpty) return 'Email é obrigatório';
        if (!value.contains('@')) return 'Email inválido';
        return null;
      },
    ),
    FieldConfig(
      label: "Senha",
      fieldName: "senha",
      icon: Icons.lock,
      isInForm: true,
      isRequired: true,
      obscureText: true,
      validator: (value) {
        if (value == null || value.isEmpty) return 'Senha é obrigatória';
        if (value.length < 6) return 'Senha deve ter pelo menos 6 caracteres';
        return null;
      },
    ),
    FieldConfig(
      label: "Nome",
      fieldName: "nome",
      icon: Icons.person,
      isFilterable: true,
      isInForm: true,
      isRequired: true,
    ),
    FieldConfig(
      label: "CPF/CNPJ",
      fieldName: "cpfCnpj",
      icon: Icons.badge,
      isFilterable: true,
      isInForm: true,
    ),
    FieldConfig(
      label: "Tipo Login",
      fieldName: "tipoLogin",
      icon: Icons.login,
      isFilterable: true,
      isInForm: true,
      fieldType: FieldType.dropdown,
      dropdownItems: LoginEnum.values
          .map((e) => {'value': e.index.toString(), 'label': e.name})
          .toList(),
    ),
  ];
}

// Enums and related classes
enum LoginEnum { ADMIN, USER, PARTNER }

class Role {
  // Add role properties
  Map<String, dynamic> toJson() => {};
  static Role fromJson(Map<String, dynamic> json) => Role();
}

class Empresa {
  // Add empresa properties
  Map<String, dynamic> toJson() => {};
  static Empresa fromJson(Map<String, dynamic> json) => Empresa();
}

class Parceiro {
  // Add parceiro properties
  Map<String, dynamic> toJson() => {};
  static Parceiro fromJson(Map<String, dynamic> json) => Parceiro();
}

class Aplicativo {
  // Add aplicativo properties
  Map<String, dynamic> toJson() => {};
  static Aplicativo fromJson(Map<String, dynamic> json) => Aplicativo();
}
